text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스를 목표로 한다.",
        "condition": "스모크 테스트 통과"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표이며 확정 릴리스 결정 아님"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토 제안이 있었으나 담당자 미지정"
      }
    ],
    "risks": [
      "잘못된 tarball 경로로 인해 릴리스 지연 가능",
      "README 설치 절차가 오래된 경우 릴리스 노트가 사용자 오해를 유발할 가능성"
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "미착수",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "미착수",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "결과 공유 이후(정확 시한 미정)",
      "status": "대기",
      "source_certainty": "확정(트리거 기반)"
    },
    {
      "owner": null,
      "task": "README 설치 절차 검토",
      "due": "목요일(가능 시)",
      "status": "담당자 미정",
      "source_certainty": "제안(비확정)"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 스모크 테스트 결과 확인",
      "스모크 결과에 따라 금요일 15:00 KST 공개 릴리스 조건 충족 여부 판정",
      "action_items.md의 실패 트리아지 노트 작성 완료 여부 확인",
      "tarball 경로 검증 결과 반영",
      "README 설치 절차 검토 담당자 지정 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 스트레치 목표 언급 여부 결정"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자",
      "미합의 마감시한"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자(owner)와 마감기한(deadline)은 명시된 경우만 확정으로 기록한다.",
    "합의되지 않은 제안은 결정으로 승격하지 않는다.",
    "내부 스트레치 목표와 공식 릴리스 목표를 혼동하지 않는다.",
    "미해결 질문은 답을 추정하지 않고 open question으로 유지한다."
  ]
}
